def set_budget(budgets, category, amount):
    """Set the budget for a category and return the stored amount."""
    budgets[category] = float(amount)
    return budgets[category]


def is_over_budget(budgets, category, subtotal):
    """Return True when a budget exists for ``category`` and ``subtotal`` exceeds it.

    Exactly at budget is not over; a category with no budget is never over.
    """
    return category in budgets and subtotal > budgets[category]


